{"name": "write_file", "arguments": {"path": "news_fetcher.py", "content": "# -*- coding: utf-8 -*-

import requests
from bs4 import BeautifulSoup
import feedparser

RSS_URLS = [
    'https://example.com/real_estate_news/rss',
    'https://example.com/tax_reform/rss',
    'https://example.com/policy_updates/rss',
    'https://example.com/law_changes/rss'
]

def fetch_news():
    news_list = []
    for url in RSS_URLS:
        response = requests.get(url)
        if response.status_code == 200:
            feed = feedparser.parse(response.content)
            for entry in feed.entries[:5]:  # Limit to the first 5 entries
                news_list.append({
                    'title': entry.title,
                    'link': entry.link,
                    'summary': entry.summary,
                    'source': url
                })
    return news_list

if __name__ == '__main__':
    news = fetch_news()
    for item in news:
        print(item)
